import React from 'react'
import HomeComponent from './HomeComponent.jsx'
import AboutComponent from './AboutComponent.jsx'
import ProjectsComponent from './ProjectsComponent.jsx'
import ContactComponent from './ContactComponent.jsx'

class BodyComponent extends React.Component {
    constructor( props ) {
        super( props )
        this.state = {
            currentPage: <AboutComponent />
        }
        this.displayPage = this.displayPage.bind( this )
    }

    displayPage( page ) {
        this.setState({
            currentPage: page
        })
    }

    render() {
        return <div className="App-body">
            <div className='App-headerMenu App-header'>
                <button className="App-headerButton" onClick={() => this.displayPage( <HomeComponent /> )}>Home</button>
                <button className="App-headerButton" onClick={() => this.displayPage( <AboutComponent /> )}>About</button>
                <button className="App-headerButton" onClick={() => this.displayPage( <ProjectsComponent /> )}>Projects</button>
                <button className="App-headerButton" onClick={() => this.displayPage( <ContactComponent /> )}>Contact</button>
            </div>
            <div className="App-body-content">
                { this.state.currentPage }
            </div>
        </div>
    }
}

export default BodyComponent